// Збирає PDF-вкладення, витягує номери авто з тіла листа,
// будує запит до Claude (використовує ЛИШЕ коносамент + інвойс).
const item = $input.item;
const bin = item.binary || {};
const j = item.json;

// 1) PDF-вкладення -> document-блоки для Claude
const docs = [];
for (const key of Object.keys(bin)) {
  const b = bin[key];
  const mt = (b.mimeType || '').toLowerCase();
  const nm = (b.fileName || '').toLowerCase();
  if (mt.includes('pdf') || nm.endsWith('.pdf')) {
    docs.push({ type: 'document', source: { type: 'base64', media_type: 'application/pdf', data: b.data } });
  }
}

// 2) Тіло листа (plain text, з фолбеком на snippet)
const textBody = (j.text || j.textPlain || j.snippet || '').toString();

// 3) Номери авто у форматі "ФСХХХХ / ВТХХХХ": до "/" = тягач, після = напівпричіп
let truck = '', trailer = '';
const m = textBody.match(/([\p{L}\p{N}\-]{3,})\s*\/\s*([\p{L}\p{N}\-]{3,})/u);
if (m) { truck = m[1].trim(); trailer = m[2].trim(); }

// 4) Заголовки листа (для відповіді на всіх)
function hdr(name) {
  if (Array.isArray(j.headers)) {
    const h = j.headers.find(x => (x.name || '').toLowerCase() === name);
    if (h) return h.value;
  }
  const cap = name.charAt(0).toUpperCase() + name.slice(1);
  return j[name] || j[cap] || '';
}
const fromAddr = hdr('from');
const ccAddr = hdr('cc');

// 5) Промпт для Claude
const prompt = 'Ти обробляєш комерційні документи на морський вантаж. У вкладеннях можуть бути різні документи (коносамент, інвойс, пакінг, сертифікати, декларація).\n' +
  'ВИКОРИСТОВУЙ ДАНІ ВИКЛЮЧНО з двох документів: Bill of Lading (коносамент) та Commercial Invoice (інвойс). Усі інші документи повністю ІГНОРУЙ, навіть якщо в них є схожі поля.\n' +
  'Поверни СТРОГО валідний JSON без пояснень і без markdown, з полями:\n' +
  '{"container":"номер контейнера з Bill of Lading","sender":"назва і повна адреса відправника (Shipper/Seller)","receiver":"назва і повна адреса отримувача (Consignee)","port":"порт прибуття/розвантаження (Port of Discharge)","weight":"вага БРУТТО (Gross Weight) з одиницею, напр. 18129.600 KG","invoice":"номер інвойсу (Invoice No.) з Commercial Invoice"}\n' +
  'Вага — ОБОВ`ЯЗКОВО брутто (Gross Weight), не нетто. Якщо поля немає — постав "".';

const content = docs.concat([{ type: 'text', text: prompt }]);

const anthropicBody = {
  model: 'claude-sonnet-5',
  max_tokens: 1024,
  messages: [{ role: 'user', content }]
};

if (docs.length === 0) {
  throw new Error('У листі немає PDF-вкладень — нема що парсити.');
}

return [{ json: {
  body: anthropicBody,
  truck, trailer,
  messageId: j.id,
  threadId: j.threadId,
  from: fromAddr,
  cc: ccAddr,
  subject: j.subject || hdr('subject')
}}];

// Розбирає JSON-відповідь Claude і формує поля + назву файлу.
const resp = $input.item.json;
let text = '';
if (resp.content && Array.isArray(resp.content)) text = resp.content.map(c => c.text || '').join('');
else text = (resp.text || '').toString();

text = text.replace(/```json/gi, '').replace(/```/g, '').trim();
let data = {};
try { data = JSON.parse(text); }
catch (e) { const mm = text.match(/\{[\s\S]*\}/); if (mm) data = JSON.parse(mm[0]); }

const prep = $('Підготовка даних').item.json;

const container = (data.container || '').toString().trim();
const receiver = (data.receiver || '').toString().trim();
// Коротка назва компанії-отримувача для імені файлу (до коми / нового рядка)
const receiverShort = receiver.split(/[,\n]/)[0].trim();
const docTitle = 'CMR draft №' + container + ' ' + receiverShort;

return [{ json: {
  container,
  sender: (data.sender || '').toString().trim(),
  receiver,
  port: (data.port || '').toString().trim(),
  weight: (data.weight || '').toString().trim(),
  invoice: (data.invoice || '').toString().trim(),
  truck: prep.truck || '',
  trailer: prep.trailer || '',
  docTitle,
  messageId: prep.messageId,
  threadId: prep.threadId,
  from: prep.from,
  cc: prep.cc,
  subject: prep.subject
}}];
